sql:
SELECT p.id, p.first_name, p.last_name
FROM person p
WHERE NOT EXISTS (
    SELECT 1 FROM knows k WHERE k.person_id = p.id
);

expected_query:
FOR a, e, p IN 0..10 OUTBOUND 'Place/111' IS_PART_OF
  SORT LENGTH(p.edges)
  RETURN { id: a.id, name: a.name, type: a.type, depth: LENGTH(p.edges) }
